/* FreeRTOS multi-tasking LED schedule */
#include "stm32f1xx_hal.h"
#include "FreeRTOS.h"
#include "task.h"

void Task1_Handler(void* params);
void Task2_Handler(void* params);

int main(void) {
  HAL_Init();

  xTaskCreate(Task1_Handler, "LED_Green", configMINIMAL_STACK_SIZE, NULL, 1, NULL);
  xTaskCreate(Task2_Handler, "LED_Red", configMINIMAL_STACK_SIZE, NULL, 1, NULL);

  vTaskStartScheduler();
  while(1);
}

void Task1_Handler(void* params) {
  while(1) {
    HAL_GPIO_TogglePin(GPIOC, GPIO_PIN_13);
    vTaskDelay(pdMS_TO_TICKS(500));
  }
}

