/* CAN Bus message frame TX initialization */
#include "stm32f1xx_hal.h"

CAN_HandleTypeDef hcan;
CAN_TxHeaderTypeDef TxHeader;
uint8_t TxData[8];
uint32_t TxMailbox;

void CAN_Config() {
  hcan.Instance = CAN1;
  // Baud rate setup: Prescaler = 9, Seg1 = 5, Seg2 = 2 for 500kbps
  HAL_CAN_Init(&hcan);
  HAL_CAN_Start(&hcan);
}

void SendFrame() {
  TxHeader.StdId = 0x123;
  TxHeader.DLC = 8;
  TxData[0] = 0xAA;
  HAL_CAN_AddTxMessage(&hcan, &TxHeader, TxData, &TxMailbox);
}

/* STM32 UART character reception using Interrupts */
#include "stm32f1xx_hal.h"

UART_HandleTypeDef huart1;
uint8_t rxBuffer[1];

void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
  if(huart->Instance == USART1) {
    // Echo byte back to sender
    HAL_UART_Transmit_IT(&huart1, rxBuffer, 1);
    // Re-enable Interrupt
    HAL_UART_Receive_IT(&huart1, rxBuffer, 1);
  }
}

int main(void) {
  HAL_Init();
  HAL_UART_Receive_IT(&huart1, rxBuffer, 1);
  while(1);
}

