/* Multi-channel 50Hz PWM Servo Setup */
#include "stm32f1xx_hal.h"

TIM_HandleTypeDef htim2;

void Servo_WriteAngle(uint8_t channel, float angle) {
  // SG90: 50Hz (20ms period). Pulse width: 0.5ms (0 deg) to 2.5ms (180 deg)
  uint32_t compareVal = (uint32_t)(500 + (angle / 180.0) * 2000);
  __HAL_TIM_SET_COMPARE(&htim2, channel, compareVal);
}

void setup() {
  HAL_TIM_PWM_Start(&htim2, TIM_CHANNEL_1);
  HAL_TIM_PWM_Start(&htim2, TIM_CHANNEL_2);
}

/* Sampling STM32 Internal Temperature Channel */
#include "stm32f1xx_hal.h"

ADC_HandleTypeDef hadc1;

float GetInternalTemp() {
  HAL_ADC_Start(&hadc1);
  if(HAL_ADC_PollForConversion(&hadc1, 100) == HAL_OK) {
    uint32_t raw = HAL_ADC_GetValue(&hadc1);
    // Calculate temp: Temp = ((V25 - VSENSE) / Avg_Slope) + 25
    // BluePill specs: V25 = 1.43V, Avg_Slope = 4.3 mV/C
    float voltage = raw * 3.3 / 4095.0;
    return ((1.43 - voltage) / 0.0043) + 25.0;
  }
  return 0.0;
}
